<svg viewBox="0 0 700 440" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="30" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">Polymarket's Access-Block Map in Europe (as of July 2026)</text>
  <g font-family="sans-serif">
    <rect x="20" y="55" width="200" height="36" rx="6" fill="#ef4444" opacity="0.9"/>
    <text x="120" y="78" fill="#111113" font-size="13" font-weight="700" text-anchor="middle">France — blocked 2024</text>
    <rect x="20" y="100" width="200" height="36" rx="6" fill="#ef4444" opacity="0.9"/>
    <text x="120" y="123" fill="#111113" font-size="13" font-weight="700" text-anchor="middle">Belgium — blocked 2025</text>
    <rect x="20" y="145" width="200" height="36" rx="6" fill="#fbbf24" opacity="0.9"/>
    <text x="120" y="168" fill="#111113" font-size="13" font-weight="700" text-anchor="middle">Spain — briefly blocked 4/2026</text>
    <rect x="20" y="190" width="200" height="36" rx="6" fill="#ef4444" opacity="0.9"/>
    <text x="120" y="213" fill="#111113" font-size="13" font-weight="700" text-anchor="middle">Italy — 2nd block (7/10)</text>

    <rect x="250" y="55" width="180" height="171" rx="6" fill="#3f3f46"/>
    <text x="340" y="78" fill="#e4e4e7" font-size="12" text-anchor="middle" font-weight="700">Europe: gambling-law frame</text>
    <text x="340" y="100" fill="#a1a1aa" font-size="11" text-anchor="middle">Joint initiative, 8-9 countries, June</text>
    <text x="340" y="118" fill="#a1a1aa" font-size="11" text-anchor="middle">Cited: player protection, integrity</text>
    <text x="340" y="145" fill="#e4e4e7" font-size="12" text-anchor="middle" font-weight="700">Gibraltar: opposite path</text>
    <text x="340" y="167" fill="#a1a1aa" font-size="11" text-anchor="middle">First dedicated prediction-market regime</text>
