    <text x="555" y="118" fill="#e4e4e7" font-size="11" text-anchor="middle">Federal law preempts NY state law</text>
    <text x="555" y="145" fill="#e4e4e7" font-size="11" text-anchor="middle">Lazio sponsorship: €19M</text>
    <text x="555" y="163" fill="#e4e4e7" font-size="11" text-anchor="middle">Now collides with Dignity Decree</text>
    <text x="555" y="185" fill="#e4e4e7" font-size="11" text-anchor="middle">ADM must refer to Rome prosecutor</text>
    <text x="555" y="207" fill="#e4e4e7" font-size="11" text-anchor="middle">First blocked 10/2025 → lifted 12/2025</text>

    <line x1="20" y1="245" x2="680" y2="245" stroke="#3f3f46" stroke-width="1"/>
